void AnalyzeAssembly(Assembly assembly)
{
    var types = assembly.GetPublicTypes();

    // 1. Extension methods for IServiceCollection and IEndpointRouteBuilder
    Console.WriteLine("--- Extension Methods ---");
    var extensionMethods = types
        .Where(t => t.IsSealed && t.IsAbstract) // static class
        .SelectMany(t => t.GetMethods(BindingFlags.Public | BindingFlags.Static))
        .Where(m => m.GetCustomAttributes(typeof(System.Runtime.CompilerServices.ExtensionAttribute), false).Length > 0)
        .OrderBy(m => m.DeclaringType?.Name + "." + m.Name)
        .ToList();

    foreach (var method in extensionMethods.Take(50))
    {
        var @params = string.Join(", ", method.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
        Console.WriteLine($"  {method.DeclaringType?.Name}.{method.Name}({@params}) -> {method.ReturnType.Name}");
    }
    if (extensionMethods.Count > 50) Console.WriteLine($"  ... and {extensionMethods.Count - 50} more");

    // 2. Attributes
    Console.WriteLine("\n--- Attributes ---");
    var attributes = types.Where(t => t.IsAttribute()).OrderBy(t => t.Name).ToList();
    foreach (var attr in attributes)
    {
        Console.WriteLine($"  {attr.FullName}");
    }

    // 3. Interfaces and classes related to resources
    Console.WriteLine("\n--- Resource-Related Types ---");
    var resourceTypes = types
        .Where(t => t.Name.Contains("Resource", StringComparison.OrdinalIgnoreCase) 
                 || t.Name.Contains("Tool", StringComparison.OrdinalIgnoreCase)
                 || t.Name.Contains("Transport", StringComparison.OrdinalIgnoreCase)
                 || t.Name.Contains("Handler", StringComparison.OrdinalIgnoreCase))
        .OrderBy(t => t.Name)
        .ToList();

    foreach (var type in resourceTypes)
    {
        var kind = type.IsInterface ? "interface" : type.IsAbstract ? "abstract class" : "class";
        Console.WriteLine($"  {kind} {type.Name}");

        // Show key methods/properties
        var members = type.GetMembers(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
            .Where(m => !(m is MethodInfo mi && (mi.IsSpecialName || mi.IsPropertyAccessor())))
            .Take(5)
            .ToList();

        foreach (var member in members)
        {
            if (member is PropertyInfo pi)
                Console.WriteLine($"    - {pi.PropertyType.Name} {pi.Name} {{ get; {(pi.CanWrite ? "set;" : "")} }}");
            else if (member is MethodInfo mi && !mi.IsSpecialName)
                Console.WriteLine($"    - {mi.ReturnType.Name} {mi.Name}()");
        }
    }

    // 4. MCP Server related types
    Console.WriteLine("\n--- MCP Server Types ---");
    var serverTypes = types
        .Where(t => t.Name.Contains("Server", StringComparison.OrdinalIgnoreCase)
                 || t.Name.Contains("Mcp", StringComparison.OrdinalIgnoreCase)
                 || t.FullName?.Contains("ModelContextProtocol.Server", StringComparison.OrdinalIgnoreCase) == true)
        .OrderBy(t => t.FullName)
        .ToList();

    foreach (var type in serverTypes.Take(20))
    {
        var kind = type.IsInterface ? "interface" : type.IsAbstract ? "abstract" : "class";
        Console.WriteLine($"  [{kind}] {type.FullName}");
    }
    if (serverTypes.Count > 20) Console.WriteLine($"  ... and {serverTypes.Count - 20} more");

    // 5. Namespaces
    Console.WriteLine("\n--- Key Namespaces ---");
    var namespaces = types.Where(t => !string.IsNullOrEmpty(t.Namespace))
        .Select(t => t.Namespace)
        .Distinct()
        .OrderBy(ns => ns)
        .ToList();

    foreach (var ns in namespaces.Take(15))
    {
        Console.WriteLine($"  {ns}");
    }
    if (namespaces.Count > 15) Console.WriteLine($"  ... and {namespaces.Count - 15} more");
}

static class ReflectionExtensions
{
    public static List<Type> GetPublicTypes(this Assembly assembly) =>
        assembly.GetTypes().Where(t => t.IsPublic && !t.IsNested).ToList();

    public static bool IsAttribute(this Type type) =>
        type.IsClass && typeof(Attribute).IsAssignableFrom(type);

    public static bool IsPropertyAccessor(this MethodInfo method) =>
        method.IsSpecialName && (method.Name.StartsWith("get_") || method.Name.StartsWith("set_"));
}
