    mcpCore.GetType("ModelContextProtocol.Server.McpServerResourceTypeAttribute"),
    mcpCore.GetType("ModelContextProtocol.Server.McpServerToolAttribute"),
    mcpCore.GetType("ModelContextProtocol.Server.McpServerToolTypeAttribute"),
};

