    Console.WriteLine($"\n[Attribute] {attr.Name}");
    var props = attr.GetProperties();
    foreach (var prop in props)
    {
        Console.WriteLine($"  - {prop.PropertyType.Name} {prop.Name} {{ get; {(prop.CanWrite ? "set;" : "")} }}");
    }
}

