if (mcpServerResource != null)
{
    Console.WriteLine($"[Abstract] {mcpServerResource.Name}");
    var props = mcpServerResource.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.IgnoreCase);
